CREATE TRIGGER [dbo].[Customer_History]ON [dbo].[Customer]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.CustomerId IS NOT NULL AND d.CustomerId IS NULL THEN 'I' 		WHEN i.CustomerId IS NOT NULL AND d.CustomerId IS NOT NULL THEN 'U' 		WHEN i.CustomerId IS NULL AND d.CustomerId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.CustomerId = d.CustomerId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_Customer([CustomerId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [CustomerId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_Customer([CustomerId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [CustomerId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND